import pytest

def test_successful_reset_invalidates_all_existing_sessions(
    api_client,                  # <fixture>
    employee_with_two_sessions,  # <fixture> yields (token, session_a, session_b, creds)
    policy_password,             # <fixture>
):
    reset_token, session_a, session_b, _creds = employee_with_two_sessions

    reset_resp = api_client.post(
        "/password/reset",
        json={"token": reset_token, "new_password": policy_password},
    )
    assert reset_resp.status_code == 200, f"Reset failed: {reset_resp.text}"

    for session_token in (session_a, session_b):
        probe = api_client.get(
            "/employee/profile",
            headers={"Authorization": f"Bearer {session_token}"},
        )
        assert probe.status_code == 401, (
            f"Session {session_token[:8]}... should be invalidated; got {probe.status_code}"
        )
